import hashlib
import os
import json
import datetime
from pathlib import Path

class FileIntegrityMonitor:
    """
    File Integrity Monitor - Detects unauthorized changes to critical OS files
    Similar to AIDE (Advanced Intrusion Detection Environment) or Tripwire
    """

    def __init__(self, baseline_file='baseline.json'):
        self.baseline_file = baseline_file
        self.baseline_db = {}
        self.monitored_files = [
            '/etc/passwd',
            '/etc/shadow',
            '/etc/sudoers',
            '/etc/ssh/sshd_config',
            '/bin/ls',
            '/bin/bash',
            '/usr/bin/sudo'
        ]

    def compute_sha256(self, filepath):
        """Compute SHA-256 hash of a file"""
        sha256_hash = hashlib.sha256()
        try:
            with open(filepath, 'rb') as f:
                for byte_block in iter(lambda: f.read(4096), b''):
                    sha256_hash.update(byte_block)
            return sha256_hash.hexdigest()
        except (IOError, OSError) as e:
            return None

    def generate_baseline(self):
        """Generate baseline hashes of all monitored files"""
        print("Generating baseline database...")
        for filepath in self.monitored_files:
            file_hash = self.compute_sha256(filepath)
            if file_hash:
                self.baseline_db[filepath] = {
                    'hash': file_hash,
                    'timestamp': datetime.datetime.now().isoformat()
                }
                print(f"  [+] {filepath}: {file_hash[:16]}...")
            else:
                print(f"  [-] {filepath}: File not accessible")

        with open(self.baseline_file, 'w') as f:
            json.dump(self.baseline_db, f, indent=2)

        print(f"Baseline saved to {self.baseline_file}")

    def load_baseline(self):
        """Load existing baseline database"""
        if os.path.exists(self.baseline_file):
            with open(self.baseline_file, 'r') as f:
                self.baseline_db = json.load(f)
            return True
        return False

    def check_integrity(self):
        """Check current file hashes against baseline"""
        if not self.load_baseline():
            print("No baseline found. Generating new baseline...")
            self.generate_baseline()
            return

        changes = {
            'modified': [],
            'deleted': [],
            'new': []
        }

        print("\nChecking file integrity...")

        # Check files in baseline
        for filepath, info in self.baseline_db.items():
            if not os.path.exists(filepath):
                changes['deleted'].append(filepath)
                print(f"  [!] DELETED: {filepath}")
            else:
                current_hash = self.compute_sha256(filepath)
                if current_hash != info['hash']:
                    changes['modified'].append(filepath)
                    print(f"  [!] MODIFIED: {filepath}")
                else:
                    print(f"  [✓] OK: {filepath}")

        # Check for new files in monitored directories
        for filepath in self.monitored_files:
            if filepath not in self.baseline_db and os.path.exists(filepath):
                changes['new'].append(filepath)
                print(f"  [!] NEW: {filepath}")

        if any(changes.values()):
            self.alert_security_team(changes)
        else:
            print("\nNo changes detected. System integrity verified.")

    def alert_security_team(self, changes):
        """Alert when changes are detected - simulates SIEM integration"""
        print("\n" + "="*50)
        print("SECURITY ALERT: File Integrity Violation Detected!")
        print("="*50)

        alert_data = {
            'timestamp': datetime.datetime.now().isoformat(),
            'alert_type': 'FILE_INTEGRITY_VIOLATION',
            'changes': changes
        }

        # In production, this would send to SIEM (CloudWatch, Splunk, etc.)
        print(json.dumps(alert_data, indent=2))

# Demo usage
if __name__ == "__main__":
    monitor = FileIntegrityMonitor()

    # First run: generate baseline
    # monitor.generate_baseline()

    # Subsequent runs: check integrity
    monitor.check_integrity()

"""
Access Control Models Demonstration
Implements DAC, MAC, and RBAC as used in cloud OS security
"""

from enum import Enum
from typing import Dict, Set, List

# ============== DAC (Discretionary Access Control) ==============
class DACPermissions(Enum):
    READ = 4
    WRITE = 2
    EXECUTE = 1

class DACSystem:
    """
    DAC - Traditional Unix file permissions (owner/group/others)
    Users control access to their own resources
    """
    def __init__(self):
        # Format: {filepath: {owner: str, group: str, perms: {user: set, group: set, other: set}}}
        self.file_acl: Dict = {}

    def set_permissions(self, filepath, owner, group, owner_perms, group_perms, other_perms):
        """Set DAC permissions on a file"""
        self.file_acl[filepath] = {
            'owner': owner,
            'group': group,
            'permissions': {
                'owner': owner_perms,
                'group': group_perms,
                'other': other_perms
            }
        }

    def check_permission(self, filepath, user, requested_permission):
        """Check if user has permission to access file"""
        if filepath not in self.file_acl:
            return False

        acl = self.file_acl[filepath]

        # Check owner permissions
        if user == acl['owner']:
            return requested_permission in acl['permissions']['owner']

        # Check group permissions
        # In real system, would check user's groups
        if user in acl.get('members', {}):
            return requested_permission in acl['permissions']['group']

        # Check other permissions
        return requested_permission in acl['permissions']['other']


# ============== MAC (Mandatory Access Control) ==============
class SELinuxContext:
    """SELinux-style security context"""
    def __init__(self, user: str, role: str, type: str, level: str):
        self.user = user
        self.role = role
        self.type = type  # e.g., httpd_t, shadow_t
        self.level = level  # e.g., s0, s1

    def __str__(self):
        return f"{self.user}:{self.role}:{self.type}:{self.level}"

class MACPolicy:
    """
    MAC - System-enforced policies that override DAC
    SELinux/AppArmor implementation concept
    """
    def __init__(self):
        # Format: {source_type: {target_type: {action: bool}}}
        self.policy_rules: Dict = {}
        self.file_contexts: Dict = {}  # {filepath: SELinuxContext}
        self.process_contexts: Dict = {}  # {pid: SELinuxContext}

    def add_rule(self, source_type, target_type, action, allowed):
        """Add MAC policy rule"""
        if source_type not in self.policy_rules:
            self.policy_rules[source_type] = {}
        if target_type not in self.policy_rules[source_type]:
            self.policy_rules[source_type][target_type] = {}
        self.policy_rules[source_type][target_type][action] = allowed

    def set_file_context(self, filepath, context: SELinuxContext):
        """Set SELinux context for a file"""
        self.file_contexts[filepath] = context

    def set_process_context(self, pid, context: SELinuxContext):
        """Set SELinux context for a process"""
        self.process_contexts[pid] = context

    def check_access(self, pid, filepath, action):
        """
        Check if process can perform action on file
        This is system-enforced, user cannot override
        """
        if pid not in self.process_contexts:
            return False  # Process has no context - denied
        if filepath not in self.file_contexts:
            return False  # No context for file - denied

        proc_ctx = self.process_contexts[pid]
        file_ctx = self.file_contexts[filepath]

        # Look up policy
        if proc_ctx.type in self.policy_rules:
            if file_ctx.type in self.policy_rules[proc_ctx.type]:
                return self.policy_rules[proc_ctx.type][file_ctx.type].get(action, False)

        return False  # Default deny


# ============== RBAC (Role-Based Access Control) ==============
class Role(Enum):
    ADMIN = "admin"
    DEVELOPER = "developer" 
    OPERATIONS = "operations"
    AUDITOR = "auditor"
    READONLY = "readonly"

class RBACSystem:
    """
    RBAC - Access based on roles rather than individual identity
    Commonly used in cloud management consoles
    """
    def __init__(self):
        # Role permissions: {role: {resource: {actions}}}
        self.role_permissions: Dict[Role, Dict[str, Set]] = {}
        # User-role assignments: {username: {roles}}
        self.user_roles: Dict[str, Set[Role]] = {}

    def assign_role(self, username: str, role: Role):
        """Assign a role to a user"""
        if username not in self.user_roles:
            self.user_roles[username] = set()
        self.user_roles[username].add(role)

    def grant_permission(self, role: Role, resource: str, action: str):
        """Grant permission to a role"""
        if role not in self.role_permissions:
            self.role_permissions[role] = {}
        if resource not in self.role_permissions[role]:
            self.role_permissions[role][resource] = set()
        self.role_permissions[role][resource].add(action)

    def check_access(self, username: str, resource: str, action: str) -> bool:
        """Check if user has permission via their roles"""
        if username not in self.user_roles:
            return False

        user_roles = self.user_roles[username]

        for role in user_roles:
            if role in self.role_permissions:
                if resource in self.role_permissions[role]:
                    if action in self.role_permissions[role][resource]:
                        return True

        return False


# ============== Demo Usage ==============
if __name__ == "__main__":
    print("=" * 60)
    print("ACCESS CONTROL MODELS DEMONSTRATION")
    print("=" * 60)

    # DAC Demo
    print("\n--- DAC (Discretionary Access Control) ---")
    dac = DACSystem()
    dac.set_permissions('/etc/shadow', 'root', 'shadow', 
                        {DACPermissions.READ, DACPermissions.WRITE},
                        {DACPermissions.READ},
                        set())
    print(f"root can read /etc/shadow: {dac.check_permission('/etc/shadow', 'root', DACPermissions.READ)}")
    print(f"alice can read /etc/shadow: {dac.check_permission('/etc/shadow', 'alice', DACPermissions.READ)}")

    # MAC Demo
    print("\n--- MAC (Mandatory Access Control - SELinux) ---")
    mac = MACPolicy()

    # Policy: httpd_t (web server) can read shadow_t files only
    mac.add_rule('httpd_t', 'shadow_t', 'read', False)  # Explicit deny
    mac.add_rule('httpd_t', 'httpd_sys_content_t', 'read', True)

    mac.set_file_context('/var/www/html', SELinuxContext('system_u', 'object_r', 'httpd_sys_content_t', 's0'))
    mac.set_file_context('/etc/shadow', SELinuxContext('system_u', 'object_r', 'shadow_t', 's0'))
    mac.set_process_context(1234, SELinuxContext('system_u', 'system_r', 'httpd_t', 's0'))

    print(f"Web server (httpd_t) can read /var/www/html: {mac.check_access(1234, '/var/www/html', 'read')}")
    print(f"Web server (httpd_t) can read /etc/shadow: {mac.check_access(1234, '/etc/shadow', 'read')}")

    # RBAC Demo
    print("\n--- RBAC (Role-Based Access Control) ---")
    rbac = RBACSystem()

    # Define permissions
    rbac.grant_permission(Role.ADMIN, 'vm:*', {'create', 'delete', 'start', 'stop', 'update'})
    rbac.grant_permission(Role.DEVELOPER, 'vm:dev', {'start', 'stop', 'logs'})
    rbac.grant_permission(Role.AUDITOR, 'vm:*', {'read', 'logs'})

    # Assign users
    rbac.assign_role('alice', Role.ADMIN)
    rbac.assign_role('bob', Role.DEVELOPER)
    rbac.assign_role('charlie', Role.AUDITOR)

    print(f"Admin (alice) can create VM: {rbac.check_access('alice', 'vm:prod', 'create')}")
    print(f"Developer (bob) can delete VM: {rbac.check_access('bob', 'vm:dev', 'delete')}")
    print(f"Auditor (charlie) can read VM: {rbac.check_access('charlie', 'vm:prod', 'read')}")

/*
 * Process Isolation Demonstration
 * Shows concepts of namespaces and cgroups used for container isolation
 * This is a conceptual demonstration - actual implementation requires root
 * 
 * Compile: gcc -o process_isolation process_isolation.c
 * Run: sudo ./process_isolation
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sched.h>
#include <sys/wait.h>
#include <sys/capability.h>
#include <errno.h>

#define STACK_SIZE (1024 * 1024)  // Stack size for child process

// Structure to demonstrate process isolation configuration
typedef struct {
    int pid_ns;      // PID namespace isolation
    int net_ns;      // Network namespace isolation
    int mnt_ns;      // Mount namespace isolation
    int user_ns;     // User namespace isolation
    int ipc_ns;      // IPC namespace isolation
    int uts_ns;      // UTS namespace isolation

    // Cgroup limits
    long cpu_limit;      // CPU limit percentage (0 = unlimited)
    long memory_limit;   // Memory limit in MB (0 = unlimited)
    int  max_processes;   // Max processes in cgroup
} IsolationConfig;

/*
 * Function to create a new PID namespace
 * In a PID namespace, processes inside have their own PID hierarchy
 */
int create_pid_namespace(void) {
    #ifdef CLONE_NEWPID
    int result = unshare(CLONE_NEWPID);
    if (result == -1) {
        perror("unshare(CLONE_NEWPID)");
        return -1;
    }
    printf("[+] Created new PID namespace\n");
    return 0;
    #else
    printf("[-] CLONE_NEWPID not supported on this system\n");
    return -1;
    #endif
}

/*
 * Function to create a new network namespace
 * Provides isolated network stack (interfaces, routing tables)
 */
int create_network_namespace(void) {
    #ifdef CLONE_NEWNET
    int result = unshare(CLONE_NEWNET);
    if (result == -1) {
        perror("unshare(CLONE_NEWNET)");
        return -1;
    }
    printf("[+] Created new network namespace\n");
    return 0;
    #else
    printf("[-] CLONE_NEWNET not supported on this system\n");
    return -1;
    #endif
}

/*
 * Function to create a mount namespace
 * Allows different processes to see different mount points
 */
int create_mount_namespace(void) {
    #ifdef CLONE_NEWNS
    int result = unshare(CLONE_NEWNS);
    if (result == -1) {
        perror("unshare(CLONE_NEWNS)");
        return -1;
    }
    printf("[+] Created new mount namespace\n");
    return 0;
    #else
    printf("[-] CLONE_NEWNS not supported on this system\n");
    return -1;
    #endif
}

/*
 * Function to create a user namespace
 * Allows mapping of UIDs/GIDs for unprivileged container users
 */
int create_user_namespace(void) {
    #ifdef CLONE_NEWUSER
    int result = unshare(CLONE_NEWUSER);
    if (result == -1) {
        perror("unshare(CLONE_NEWUSER)");
        return -1;
    }
    printf("[+] Created new user namespace\n");
    return 0;
    #else
    printf("[-] CLONE_NEWUSER not supported on this system\n");
    return -1;
